1	package doctor
2	
3	import (
4		"fmt"
5		"io"
6		"os"
7		"runtime"
8		"sort"
9		"strings"
10	
11		"github.com/an-lee/gh-sr/internal/config"
12		"github.com/an-lee/gh-sr/internal/host"
13		"github.com/an-lee/gh-sr/internal/runner"
14	)
15	
16	const (
17		sevOK   = "OK"
18		sevWarn = "WARN"
19		sevFail = "FAIL"
20	)
21	
22	// Result aggregates doctor check outcomes for exit code decisions.
23	type Result struct {
24		Fail int
25		Warn int
26	}
27	
28	// ExitCode returns a process exit code: 1 if any FAIL, or if strict and any WARN.
29	func ExitCode(res Result, strict bool) int {
30		if res.Fail > 0 {
31			return 1
32		}
33		if strict && res.Warn > 0 {
34			return 1
35		}
36		return 0
37	}
38	
39	// Run prints diagnostics to w. cfg and cfgErr come from config.LoadFromPath (or Load) after BootstrapEnv.
40	// hasGitHubToken is true when gh CLI credentials yielded a token for github.com.
41	// If cfg is nil (load error), GitHub and host checks are skipped after the configuration section.
42	func Run(w io.Writer, cfgPath, envPath string, cfg *config.Config, cfgErr error, gh *runner.GitHubClient, hasGitHubToken bool, filterHost, filterRepo string, strict bool) Result {
43		var r Result
44	
45		fmt.Fprintln(w, "=== Local environment ===")
46	
47		if _, err := os.Stat(cfgPath); err != nil {
48			printLine(w, sevFail, "local", fmt.Sprintf("config path: %v", err))
49			r.Fail++
50		} else {
51			printLine(w, sevOK, "local", fmt.Sprintf("config file exists: %s", cfgPath))
52		}
53	
54		switch _, err := os.Stat(envPath); {
55		case os.IsNotExist(err):
56			printLine(w, sevWarn, "local", fmt.Sprintf("env file not found: %s (optional)", envPath))
57			r.Warn++
58		case err != nil:
59			printLine(w, sevWarn, "local", fmt.Sprintf("env file: %v", err))
60			r.Warn++
61		default:
62			printLine(w, sevOK, "local", fmt.Sprintf("env file present: %s", envPath))
63		}
64	
65		if hasGitHubToken {
66			printLine(w, sevOK, "local", "GitHub token: from gh CLI (gh auth login)")
67		} else {
68			printLine(w, sevFail, "local", "GitHub token: not found; run `gh auth login`")
69			r.Fail++
70		}
71	
72		needSSH := cfg == nil
73		if cfg != nil {
74			for _, rc := range config.FilterRunners(cfg, filterHost, filterRepo, nil) {
75				hc := cfg.Hosts[rc.Host]
76				if !config.IsLocalAddr(hc.Addr) {
77					needSSH = true
78					break
79				}
80			}
81		}
82		if needSSH {
83			if host.HasSSHAuth() {
84				printLine(w, sevOK, "local", "SSH client auth available (agent or default ~/.ssh keys)")
85			} else {
86				printLine(w, sevWarn, "local", "no SSH agent (SSH_AUTH_SOCK) or default ~/.ssh keys; required for remote hosts")
87				r.Warn++
88			}
89		} else {
90			printLine(w, sevOK, "local", "only local hosts in scope; SSH client keys not required")
91		}
92	
93		fmt.Fprintln(w, "\n=== Configuration ===")
94		if cfgErr != nil {
95			printLine(w, sevFail, "config", cfgErr.Error())
96			r.Fail++
97			printSummary(w, r, strict)
98			return r
99		}
100		printLine(w, sevOK, "config", "YAML valid and constraints satisfied")
101	
102		runners := config.FilterRunners(cfg, filterHost, filterRepo, nil)
103		if len(runners) == 0 {
104			printLine(w, sevWarn, "config", "no runners match --host / --repo filters")
105			r.Warn++
106			printSummary(w, r, strict)
107			return r
108		}
109	
110		fmt.Fprintln(w, "\n=== GitHub API ===")
111		if gh == nil {
112			printLine(w, sevFail, "github", "skipped: no GitHub token (run `gh auth login`)")
113			r.Fail++
114		} else {
115			repos := uniqueRepos(runners)
116			for _, repo := range repos {
117				list, err := gh.ListRunners(repo)
118				if err != nil {
119					printLine(w, sevFail, "github", fmt.Sprintf("%s: %v", repo, err))
120					r.Fail++
121					continue
122				}
123				printLine(w, sevOK, "github", fmt.Sprintf("%s: list runners OK (%d registered)", repo, len(list)))
124			}
125			orgs := uniqueOrgs(runners)
126			for _, org := range orgs {
127				list, err := gh.ListRunnersScoped("org", org)
128				if err != nil {
129					printLine(w, sevFail, "github", fmt.Sprintf("org %s: %v", org, err))
130					r.Fail++
131					continue
132				}
133				printLine(w, sevOK, "github", fmt.Sprintf("org %s: list runners OK (%d registered)", org, len(list)))
134			}
135		}
136	
137		fmt.Fprintln(w, "\n=== Hosts ===")
138		hostOrder := uniqueHostNames(runners)
139		for _, hostName := range hostOrder {
140			hcfg := cfg.Hosts[hostName]
141	
142			h := host.NewHost(hostName, hcfg)
143			if err := h.Connect(); err != nil {
144				printLine(w, sevFail, hostName, fmt.Sprintf("connect: %v", err))
145				r.Fail++
146				continue
147			}
148			if err := ensureDoctorHostOS(h, hcfg.Addr); err != nil {
149				printLine(w, sevFail, hostName, fmt.Sprintf("detect os: %v", err))
150				r.Fail++
151				_ = h.Close()
152				continue
153			}
154	
155			func() {
156				defer h.Close()
157				printLine(w, sevOK, hostName, fmt.Sprintf("connected (%s)", addrSummary(hcfg.Addr)))
158				checkNative(w, hostName, h, &r)
159				checkNativeRunnerInstall(w, hostName, h, runners, &r)
160				if h.OS == "linux" {
161					checkLinuxSudo(w, hostName, h, &r)
162				}
163				if hasAgenticRunners(cfg.RunnersForHost(hostName)) {
164					checkAgenticPrereqs(w, hostName, h, &r)
165				}
166			}()
167		}
168	
169		printSummary(w, r, strict)
170		return r
171	}
172	
173	func printLine(w io.Writer, sev, scope, msg string) {
174		fmt.Fprintf(w, "%-5s [%-12s] %s\n", sev, scope, msg)
175	}
176	
177	func printSummary(w io.Writer, r Result, strict bool) {
178		fmt.Fprintln(w, "\n--- Summary ---")
179		fmt.Fprintf(w, "%d failed, %d warnings", r.Fail, r.Warn)
180		if strict {
181			fmt.Fprint(w, " (strict: warnings fail the run)")
182		}
183		fmt.Fprintln(w)
184	}
185	
186	func addrSummary(addr string) string {
187		if config.IsLocalAddr(addr) {
188			return "local"
189		}
190		return "ssh " + addr
191	}
192	
193	// ensureDoctorHostOS sets h.OS when empty: local hosts use runtime.GOOS; remote hosts use DetectOS over the existing connection.
194	func ensureDoctorHostOS(h *host.Host, addr string) error {
195		if h.OS != "" {
196			return nil
197		}
198		if config.IsLocalAddr(addr) {
199			h.OS = runtime.GOOS
200			return nil
201		}
202		detected, err := host.DetectOS(h)
203		if err != nil {
204			return err
205		}
206		h.OS = detected
207		return nil
208	}
209	
210	func uniqueRepos(runners []config.RunnerConfig) []string {
211		seen := make(map[string]struct{})
212		for _, rc := range runners {
213			if rc.Repo != "" {
214				seen[rc.Repo] = struct{}{}
215			}
216		}
217		out := make([]string, 0, len(seen))
218		for repo := range seen {
219			out = append(out, repo)
220		}
221		sort.Strings(out)
222		return out
223	}
224	
225	func uniqueOrgs(runners []config.RunnerConfig) []string {
226		seen := make(map[string]struct{})
227		for _, rc := range runners {
228			if rc.Org != "" {
229				seen[rc.Org] = struct{}{}
230			}
231		}
232		out := make([]string, 0, len(seen))
233		for org := range seen {
234			out = append(out, org)
235		}
236		sort.Strings(out)
237		return out
238	}
239	
240	func uniqueHostNames(runners []config.RunnerConfig) []string {
241		seen := make(map[string]struct{})
242		for _, rc := range runners {
243			seen[rc.Host] = struct{}{}
244		}
245		out := make([]string, 0, len(seen))
246		for name := range seen {
247			out = append(out, name)
248		}
249		sort.Strings(out)
250		return out
251	}
252	
253	// nativeInstallTargetsForHost lists (instanceName, runnerConfigName) for native-mode runners on hostName.
254	func nativeInstallTargetsForHost(runners []config.RunnerConfig, hostName string) [][2]string {
255		var out [][2]string
256		for _, rc := range runners {
257			if rc.Host != hostName {
258				continue
259			}
260			for _, inst := range rc.InstanceNames() {
261				out = append(out, [2]string{inst, rc.Name})
262			}
263		}
264		return out
265	}
266	
267	func checkNativeRunnerInstall(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
268		for _, pair := range nativeInstallTargetsForHost(runners, hostName) {
269			inst, runnerName := pair[0], pair[1]
270			dir := h.RunnerDir(inst)
271			ok, err := runner.NativeRunnerConfigPresent(h, inst)
272			if err != nil {
273				printLine(w, sevFail, hostName, fmt.Sprintf("native: instance %s: %v", inst, err))
274				r.Fail++
275				continue
276			}
277			if !ok {
278				printLine(w, sevFail, hostName, fmt.Sprintf("native: instance %s not installed (missing .runner under %s); run: gh sr setup %s", inst, dir, runnerName))
279				r.Fail++
280				continue
281			}
282			printLine(w, sevOK, hostName, fmt.Sprintf("native: instance %s installed", inst))
283		}
284	}
285	
286	func checkNative(w io.Writer, hostName string, h *host.Host, r *Result) {
287		switch h.OS {
288		case "linux":
289			out, err := h.Run(`if command -v curl >/dev/null 2>&1 && command -v tar >/dev/null 2>&1; then echo ok; else echo missing; fi`)
290			out = strings.TrimSpace(out)
291			if err != nil || out != "ok" {
292				printLine(w, sevFail, hostName, fmt.Sprintf("native: need curl and tar on PATH (%v)", err))
293				r.Fail++
294				return
295			}
296			printLine(w, sevOK, hostName, "native: curl and tar present")
297		case "darwin":
298			out, err := h.Run(`command -v curl >/dev/null 2>&1 && echo ok || echo missing`)
299			out = strings.TrimSpace(out)
300			if err != nil || out != "ok" {
301				printLine(w, sevFail, hostName, fmt.Sprintf("native: need curl (%v)", err))
302				r.Fail++
303				return
304			}
305			printLine(w, sevOK, hostName, "native: curl present")
306		case "windows":
307			out, err := h.RunShell(`$PSVersionTable.PSVersion.ToString()`)
308			out = strings.TrimSpace(out)
309			if err != nil || out == "" {
310				printLine(w, sevFail, hostName, fmt.Sprintf("native: PowerShell check failed (%v)", err))
311				r.Fail++
312				return
313			}
314			printLine(w, sevOK, hostName, fmt.Sprintf("native: PowerShell %s", out))
315		default:
316			printLine(w, sevWarn, hostName, fmt.Sprintf("native: unknown os %q", h.OS))
317			r.Warn++
318		}
319	}
320	
321	func checkLinuxSudo(w io.Writer, hostName string, h *host.Host, r *Result) {
322		uid, err := h.Run(`id -u`)
323		if err != nil {
324			printLine(w, sevWarn, hostName, fmt.Sprintf("linux: could not check uid: %v", err))
325			r.Warn++
326			return
327		}
328		if strings.TrimSpace(uid) == "0" {
329			return
330		}
331		out, err := h.Run(`sudo -n true 2>/dev/null && echo ok || echo no`)
332		out = strings.TrimSpace(out)
333		if err != nil || out != "ok" {
334			printLine(w, sevWarn, hostName, "linux: passwordless sudo not available; gh sr setup/update may fail for package installs")
335			r.Warn++
336			return
337		}
338		printLine(w, sevOK, hostName, "linux: non-root user has passwordless sudo")
339	}
340	
341	// hasAgenticRunners returns true if any runner in the list uses the agentic profile.
342	func hasAgenticRunners(runners []config.RunnerConfig) bool {
343		for _, rc := range runners {
344			if rc.IsAgentic() {
345				return true
346			}
347		}
348		return false
349	}
350	
351	// checkAgenticPrereqs verifies Docker is available on the host for agentic workflow containers.
352	// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
353	func checkAgenticPrereqs(w io.Writer, hostName string, h *host.Host, r *Result) {
354		if h.OS != "linux" {
355			printLine(w, sevFail, hostName, "agentic: gh-aw only supported on Linux hosts")
356			r.Fail++
357			return
358		}
359	
360		// Check docker CLI.
361		out, err := h.Run(`docker --version 2>/dev/null`)
362		if err != nil || !strings.Contains(out, "Docker version") {
363			printLine(w, sevFail, hostName, "agentic: docker CLI not found on PATH; gh-aw requires Docker to be pre-installed on the host")
364			r.Fail++
365			return
366		}
367		printLine(w, sevOK, hostName, fmt.Sprintf("agentic: docker CLI %s", strings.TrimSpace(out)))
368	
369		// Check docker daemon is running.
370		out, err = h.Run(`docker info 2>/dev/null`)
371		if err != nil {
372			printLine(w, sevFail, hostName, "agentic: docker daemon not running (docker info failed); start docker or ensure it starts at boot")
373			r.Fail++
374			return
375		}
376		printLine(w, sevOK, hostName, "agentic: docker daemon running")
377	
378		// Check docker compose plugin.
379		out, err = h.Run(`docker compose version 2>/dev/null`)
380		if err != nil {
381			printLine(w, sevWarn, hostName, "agentic: docker compose plugin not found (docker compose version failed); gh-aw may need it for multi-container setup")
382			r.Warn++
383		} else {
384			printLine(w, sevOK, hostName, fmt.Sprintf("agentic: docker compose %s", strings.TrimSpace(out)))
385		}
386	
387		// Check iptables is available.
388		out, err = h.Run(`command -v iptables >/dev/null 2>&1 && echo ok || echo missing`)
389		if err != nil || strings.TrimSpace(out) != "ok" {
390			printLine(w, sevFail, hostName, "agentic: iptables not found on PATH; gh-aw needs it for network egress control (DOCKER-USER chain)")
391			r.Fail++
392			return
393		}
394		printLine(w, sevOK, hostName, "agentic: iptables available")
395	
396		// Check DOCKER-USER chain exists (gh-aw creates it).
397		out, err = h.Run(`iptables -L DOCKER-USER 2>/dev/null && echo exists || echo missing`)
398		if err != nil || strings.TrimSpace(out) != "exists" {
399			printLine(w, sevWarn, hostName, "agentic: DOCKER-USER chain not found; gh-aw creates it on first run; ensure passwordless sudo for iptables")
400			r.Warn++
401		} else {
402			printLine(w, sevOK, hostName, "agentic: DOCKER-USER chain exists")
403		}
404	
405		// Check RUNNER_TEMP for agentic runners.
406		// gh-aw uses /tmp/gh-aw for its runtime tree. If the runner's RUNNER_TEMP is /tmp,
407		// bind mounts and security isolation will conflict with gh-aw's own files.
408		out, err = h.Run(`echo "${RUNNER_TEMP:-}"`)
409		if err == nil {
410			rt := strings.TrimSpace(out)
411			if rt == "/tmp" {
412				printLine(w, sevWarn, hostName, "agentic: RUNNER_TEMP=/tmp conflicts with gh-aw runtime tree at /tmp/gh-aw (mount and isolation conflicts)")
413				printLine(w, sevWarn, hostName, "agentic: fix: set RUNNER_TEMP to a path under the runner work directory, e.g. ~/.gh-sr/runners/<name>/_work/_temp")
414				r.Warn++
415			}
416		}
417	
418		// Check passwordless sudo for iptables (needed for gh-aw egress rules).
419		uid, err := h.Run(`id -u`)
420		if err != nil {
421			printLine(w, sevWarn, hostName, fmt.Sprintf("agentic: could not check uid for iptables sudo: %v", err))
422			r.Warn++
423			return
424		}
425		if strings.TrimSpace(uid) != "0" {
426			out, err = h.Run(`sudo -n iptables -L DOCKER-USER >/dev/null 2>&1 && echo ok || echo no`)
427			if err != nil || strings.TrimSpace(out) != "ok" {
428				printLine(w, sevWarn, hostName, "agentic: passwordless sudo for iptables not available; gh-aw may fail to set egress rules")
429				r.Warn++
430				return
431			}
432			printLine(w, sevOK, hostName, "agentic: passwordless sudo for iptables available")
433		}
434	
435		// Check host.docker.internal resolution inside containers.
436		// gh-aw relies on host.docker.internal to reach the MCP gateway from agent containers.
437		out, err = h.Run(`docker run --rm alpine sh -c "getent hosts host.docker.internal || echo failed" 2>/dev/null`)
438		out = strings.TrimSpace(out)
439		if err != nil || out == "failed" || out == "" {
440			printLine(w, sevFail, hostName, "agentic: host.docker.internal does not resolve inside containers; configure Docker DNS (see README)")
441			r.Fail++
442		} else if strings.Contains(out, "127.0.0.1") {
443			printLine(w, sevFail, hostName, "agentic: host.docker.internal resolves to 127.0.0.1 inside containers; this breaks gh-aw MCP gateway (see README)")
444			r.Fail++
445		} else {
446			fields := strings.Fields(out)
447			ip := ""
448			if len(fields) > 0 {
449				ip = fields[0]
450			}
451			printLine(w, sevOK, hostName, fmt.Sprintf("agentic: host.docker.internal resolves correctly inside containers (%s)", ip))
452		}
453	
454		// Check general DNS resolution inside containers.
455		// If dnsmasq is configured without upstream servers, it only answers static records
456		// and REFUSES everything else, breaking external API access (model providers, etc.).
457		out, err = h.Run(`docker run --rm alpine sh -c "nslookup github.com >/dev/null 2>&1 && echo ok || echo failed" 2>/dev/null`)
458		out = strings.TrimSpace(out)
459		if err != nil || out != "ok" {
460			printLine(w, sevFail, hostName, "agentic: external DNS (github.com) does not resolve inside containers; check Docker DNS / dnsmasq upstream server config (see README)")
461			r.Fail++
462		} else {
463			printLine(w, sevOK, hostName, "agentic: external DNS resolves inside containers")
464		}
465	}
