182		for _, name := range rc.InstanceNames() {
183			dir := h.RunnerDir(name)
184	
185			installed, _ := NativeRunnerConfigPresent(h, name)
186			if installed {
187				fmt.Fprintf(m.out(), "  %s: already installed, skipping\n", name)
188				continue
189			}
190	
191			fmt.Fprintf(m.out(), "  %s: installing runner v%s...\n", name, version)
192	
193			if h.OS == "linux" {
194				installDepsCmd := linuxElevatePrelude + `
195					if ! command -v curl >/dev/null 2>&1 || ! command -v tar >/dev/null 2>&1; then
196						if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl tar;
197						elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl tar;
198						elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl tar;
199						fi
200					fi
201				`
202				if _, err := h.Run(installDepsCmd); err != nil {
203					fmt.Fprintf(m.out(), "  %s: warning: failed to ensure curl/tar are installed: %v\n", name, err)
204				}
205			}
