214				fmt.Fprintf(m.out(), "  %s: downloading runner v%s...\n", name, version)
215				if _, err := h.Run(fmt.Sprintf("mkdir -p %s", dir)); err != nil {
216					return fmt.Errorf("creating runner directory: %w", err)
217				}
218				cmds := fmt.Sprintf(
219					"cd %s && tarball=%s && rm -f \"$tarball\" && "+
220						"curl -fSL --retry 3 --retry-delay 2 -o \"$tarball\" '%s'",
221					dir, tarball, url,
222				)
223				if _, err := h.Run(cmds); err != nil {
224					return fmt.Errorf("downloading runner: %w", err)
225				}
226				fmt.Fprintf(m.out(), "  %s: extracting runner...\n", name)
227				cmds = fmt.Sprintf("cd %s && tarball=%s && tar xzf \"$tarball\" && rm -f \"$tarball\"", dir, tarball)
228				if _, err := h.Run(cmds); err != nil {
229					return fmt.Errorf("extracting runner: %w", err)
230				}
231			}
232	
233			if h.OS == "linux" {
234				fmt.Fprintf(m.out(), "  %s: installing runner dependencies...\n", name)
235				depsCmd := fmt.Sprintf(
236					"cd %s && %s && $SUDO ./bin/installdependencies.sh",
237					dir, strings.TrimSpace(linuxElevatePrelude),
238				)
239				if _, err := h.Run(depsCmd); err != nil {
240					fmt.Fprintf(m.out(), "  %s: warning: failed to install runner dependencies: %v\n", name, err)
241				}
242			}
243	
244			regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
245			if err != nil {
246				return err
247			}
248	
249			labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
250	
251			fmt.Fprintf(m.out(), "  %s: registering runner with GitHub...\n", name)
252			if h.OS == "windows" {
253				if _, err := h.RunShell(windowsNativeConfigScript(h, rc, name, regToken)); err != nil {
254					return fmt.Errorf("configuring runner on Windows: %w", err)
255				}
256			} else {
257				configURL := nativeConfigURL(rc)
258				configCmd := fmt.Sprintf(
259					"cd %s && ./config.sh --unattended --url '%s' --token '%s' --name '%s' --labels '%s' --work '_work' --replace",
260					dir, configURL, regToken, name, labels,
261				)
262				if rc.Group != "" {
263					configCmd += fmt.Sprintf(" --runnergroup '%s'", rc.Group)
264				}
265				if rc.Ephemeral {
266					configCmd += " --ephemeral"
267				}
268				if _, err := h.Run(configCmd); err != nil {
269					return fmt.Errorf("configuring runner: %w", err)
270				}
271			}
272	
273			fmt.Fprintf(m.out(), "  %s: configured\n", name)
274		}
275	
276		// For agentic runners, install gh-aw CLI on the host.
277		// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
278		if rc.IsAgentic() && h.OS == "linux" {
279			// Pre-flight check: warn if the runner user lacks passwordless sudo.
280			// gh-aw requires sudo to manage iptables (DOCKER-USER chain) and awf-net bridge.
281			warnAgenticSudoPrereqs(h, m.out(), rc.Name)
282	
283			// Clean up zombie Docker resources from previously crashed gh-aw jobs.
284			// If a job crashes, orphaned gh-aw containers and networks block the next job.
285			fmt.Fprintf(m.out(), "  %s: cleaning up zombie gh-aw Docker resources...\n", rc.Name)
286			cleanupOut, cleanupErr := h.Run(`
287	docker ps -a --filter "name=gh-aw" --format '{{.ID}}' 2>/dev/null | xargs -r docker rm -f 2>/dev/null
288	docker network ls --filter "name=gh-aw" --format '{{.ID}}' 2>/dev/null | xargs -r docker network rm 2>/dev/null
289	docker network prune -f 2>/dev/null
290	echo "cleanup done"
291	`)
292			if cleanupErr != nil {
293				fmt.Fprintf(m.out(), "  %s: warning: Docker cleanup failed: %v\n", rc.Name, cleanupErr)
294			} else if strings.TrimSpace(cleanupOut) != "" {
295				fmt.Fprintf(m.out(), "  %s: Docker cleanup: %s\n", rc.Name, strings.TrimSpace(cleanupOut))
296			}
297	
298			fmt.Fprintf(m.out(), "  %s: installing gh-aw CLI for agentic profile...\n", rc.Name)
299			installGHAWCmd := `if [ -d ~/.local/share/gh/extensions/gh-aw ]; then
300				echo "gh-aw already installed"
301			else
302				curl -sL https://raw.githubusercontent.com/github/gh-aw/main/install-gh-aw.sh | bash
303			fi`
304			out, err := h.Run(installGHAWCmd)
305			if err != nil {
306				fmt.Fprintf(m.out(), "  %s: warning: failed to install gh-aw CLI: %v\n", rc.Name, err)
307			} else {
308				fmt.Fprintf(m.out(), "  %s: gh-aw CLI installed\n", rc.Name)
309				if out != "" {
310					fmt.Fprintf(m.out(), "  %s: gh-aw: %s\n", rc.Name, strings.TrimSpace(out))
311				}
312			}
313	
314			// Set up /opt/hostedtoolcache for gh-aw agent containers.
315			// gh-aw searches for tools (e.g., claude) in /opt/hostedtoolcache, which exists on
316			// GitHub Hosted Runners but not on self-hosted runners. We create a bind mount so
317			// agent containers can find npm-installed tools.
318			fmt.Fprintf(m.out(), "  %s: setting up /opt/hostedtoolcache for agentic workflows...\n", rc.Name)
319			npmPrefixCmd := `npm config get prefix 2>/dev/null || echo "/usr/local"`
320			npmPrefix, err := h.Run(npmPrefixCmd)
321			if err != nil {
322				fmt.Fprintf(m.out(), "  %s: warning: failed to detect npm prefix: %v\n", rc.Name, err)
323			} else {
324				npmPrefix = strings.TrimSpace(npmPrefix)
325				hostedtoolcacheSetup := fmt.Sprintf(`%s
326				if [ -d /opt/hostedtoolcache ]; then
327					if [ -L /opt/hostedtoolcache ]; then
328						if [ "$(readlink -f /opt/hostedtoolcache)" != "%s" ]; then
329							echo "Updating /opt/hostedtoolcache symlink to %s"
330							$SUDO rm -f /opt/hostedtoolcache
331							$SUDO mkdir -p /opt/hostedtoolcache
332							$SUDO mount --bind %s /opt/hostedtoolcache
333						else
334							echo "/opt/hostedtoolcache already correctly configured"
335						fi
336					else
337						echo "/opt/hostedtoolcache already exists as a directory"
338					fi
339				else
340					echo "Creating /opt/hostedtoolcache -> %s"
341					$SUDO mkdir -p /opt/hostedtoolcache
342					$SUDO mount --bind %s /opt/hostedtoolcache
343					if ! grep -q "^%s" /etc/fstab 2>/dev/null; then
344						echo "%s /opt/hostedtoolcache none defaults,bind 0 0" | $SUDO tee -a /etc/fstab
345					fi
346				fi`, linuxElevatePrelude, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix)
347				out, err := h.Run(hostedtoolcacheSetup)
348				if err != nil {
349					fmt.Fprintf(m.out(), "  %s: warning: failed to set up /opt/hostedtoolcache: %v\n", rc.Name, err)
350				} else {
351					fmt.Fprintf(m.out(), "  %s: /opt/hostedtoolcache configured\n", rc.Name)
352					if out != "" {
353						fmt.Fprintf(m.out(), "  %s: hostedtoolcache: %s\n", rc.Name, strings.TrimSpace(out))
354					}
355				}
356			}
357	
358			// Set up Docker DNS for agentic workflows.
359			// Agent containers (gh-aw) use host.docker.internal to reach the MCP Gateway running
360			// on the host network. Linux Docker does not resolve this by default; we configure
361			// dnsmasq as a local DNS resolver that answers host.docker.internal from the docker0
362			// bridge IP and forwards everything else upstream. This also ensures external DNS
363			// (model provider APIs, GitHub, etc.) works from inside agent containers.
364			fmt.Fprintf(m.out(), "  %s: setting up Docker DNS for agentic workflows...\n", rc.Name)
365			if err := m.setupAgenticDNS(h, rc.Name); err != nil {
366				fmt.Fprintf(m.out(), "  %s: warning: Docker DNS setup failed: %v\n", rc.Name, err)
367			}
368	
369			// Pre-pull critical gh-aw images to reduce first-job startup latency.
370			// These images are required by every agentic workflow run and can be several hundred MB.
371			fmt.Fprintf(m.out(), "  %s: pre-pulling gh-aw images (this may take a few minutes)...\n", rc.Name)
372			for _, img := range []string{
373				"ghcr.io/github/gh-aw-firewall/agent:latest",
374				"ghcr.io/github/gh-aw-mcpg:latest",
375			} {
376				pullOut, pullErr := h.Run(fmt.Sprintf("docker pull %s 2>&1", img))
377				pullOut = strings.TrimSpace(pullOut)
378				if pullErr != nil {
379					fmt.Fprintf(m.out(), "  %s: warning: failed to pull %s: %v\n", rc.Name, img, pullErr)
380					if pullOut != "" {
381						fmt.Fprintf(m.out(), "  %s:   %s\n", rc.Name, pullOut)
382					}
383				} else {
384					// Show the final status line (e.g. "Status: Image is up to date for ...")
385					lines := strings.Split(pullOut, "\n")
386					statusLine := pullOut
387					for i := len(lines) - 1; i >= 0; i-- {
388						if l := strings.TrimSpace(lines[i]); l != "" {
389							statusLine = l
390							break
391						}
392					}
393					fmt.Fprintf(m.out(), "  %s: pulled %s: %s\n", rc.Name, img, statusLine)
394				}
395			}
396		}
397	
398		return nil
399	}
