401	func (m *Manager) startNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
402		return m.startNativeOnce(h, rc, instanceName, true)
403	}
404	
405	// startNativeOnce starts the runner and optionally detects a stale registration.
406	// When retryOnStale is true and the runner exits immediately with the stale-registration
407	// message, it clears local credentials, re-runs setupNative, and retries once.
408	func (m *Manager) startNativeOnce(h *host.Host, rc config.RunnerConfig, instanceName string, retryOnStale bool) error {
409		dir := h.RunnerDir(instanceName)
410	
411		ok, err := NativeRunnerConfigPresent(h, instanceName)
412		if err != nil {
413			return fmt.Errorf("checking runner install at %s: %w", dir, err)
414		}
415		if !ok {
416			fmt.Fprintf(m.out(), "  %s: not installed, running setup (this takes a few minutes)...\n", instanceName)
417			if setupErr := m.setupNative(h, rc); setupErr != nil {
418				return fmt.Errorf("auto-setup for %s: %w", instanceName, setupErr)
419			}
420		}
421	
422		if h.OS == "windows" {
423			out, err := h.RunShell(windowsNativeStartScript(h, instanceName))
424			if err != nil {
425				return err
426			}
427			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
428	
429			if retryOnStale {
430				fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
431				checkOut, _ := h.RunShell(windowsCheckStaleRegistration(h, instanceName))
432				if strings.TrimSpace(checkOut) == "stale" {
433					return m.handleStaleRegistration(h, rc, instanceName)
434				}
435			}
436			return nil
437		}
438	
439		// Unix (Linux / macOS)
440		cmd := fmt.Sprintf(
441			`cd %s; pid_file=".runner_pid"; `+
442				`if [ -f "$pid_file" ] && kill -0 "$(cat "$pid_file")" 2>/dev/null; then echo "already running"; exit 0; fi; `+
443				`nohup ./run.sh > runner.log 2>&1 & { echo $!; } > "$pid_file"; echo "started PID $!"`,
444			dir,
445		)
446		out, err := h.Run(cmd)
447		if err != nil {
448			return err
449		}
450		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
451	
452		if retryOnStale {
453			fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
454			checkCmd := fmt.Sprintf(
455				`sleep 5 && cd %s && pid=$(cat .runner_pid 2>/dev/null) && `+
456					`if [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null; then echo ok; `+
457					`elif grep -q %q runner.log 2>/dev/null; then echo stale; `+
458					`else echo ok; fi`,
459				dir, staleRegistrationMsg,
460			)
461			checkOut, _ := h.Run(checkCmd)
462			if strings.TrimSpace(checkOut) == "stale" {
463				return m.handleStaleRegistration(h, rc, instanceName)
464			}
465		}
466		return nil
467	}
468	
469	func (m *Manager) handleStaleRegistration(h *host.Host, rc config.RunnerConfig, instanceName string) error {
470		fmt.Fprintf(m.out(), "  %s: registration expired on GitHub, re-configuring...\n", instanceName)
471		dir := h.RunnerDir(instanceName)
472	
473		if h.OS == "windows" {
474			h.RunShell(windowsDeleteRunnerConfig(h, instanceName))
475		} else {
476			h.Run(fmt.Sprintf("rm -f %s/.runner %s/.credentials %s/.credentials_rsaparams", dir, dir, dir))
477		}
478	
479		if err := m.setupNative(h, rc); err != nil {
480			return fmt.Errorf("re-configuring after stale registration: %w", err)
481		}
482	
483		return m.startNativeOnce(h, rc, instanceName, false)
484	}
