486	func (m *Manager) stopNative(h *host.Host, instanceName string) error {
487		dir := h.RunnerDir(instanceName)
488	
489		if h.OS == "windows" {
490			cmd := fmt.Sprintf(
491				"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
492					"if (-not (Test-Path $pidFile)) { Write-Host 'not running'; exit 0 }; "+
493					"$p = (Get-Content $pidFile | Select-Object -First 1).Trim(); "+
494					"$null = & taskkill.exe /PID $p /T /F 2>&1; "+
495					"if ($LASTEXITCODE -eq 0) { Write-Host 'stopped' } else { Write-Host 'not running' }; "+
496					"Remove-Item $pidFile -Force -EA SilentlyContinue",
497				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
498			)
499			out, err := h.RunShell(cmd)
500			if err != nil {
501				return err
502			}
503			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
504			return nil
505		}
506	
507		cmd := fmt.Sprintf(
508			`cd %s && pid_file=".runner_pid" && `+
509				`if [ ! -f "$pid_file" ]; then echo "not running"; exit 0; fi && `+
510				`pid=$(cat "$pid_file") && `+
511				`if ! kill -0 "$pid" 2>/dev/null; then echo "not running"; rm -f "$pid_file"; exit 0; fi && `+
512				`kill "$pid" && `+
513				`for i in $(seq 1 10); do kill -0 "$pid" 2>/dev/null || break; sleep 1; done && `+
514				`kill -0 "$pid" 2>/dev/null && kill -9 "$pid" 2>/dev/null; `+
515				`rm -f "$pid_file" && echo "stopped"`,
516			dir,
517		)
518		out, err := h.Run(cmd)
519		if err != nil {
520			return err
521		}
522		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
523		return nil
524	}
