526	func (m *Manager) removeNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
527		dir := h.RunnerDir(instanceName)
528	
529		_ = m.stopNative(h, instanceName)
530	
531		removeToken, err := m.GitHub.GetRemovalTokenScoped(rc.Scope(), rc.ScopeTarget())
532		if err != nil {
533			fmt.Fprintf(m.out(), "  %s: warning: could not get removal token: %v\n", instanceName, err)
534		} else {
535			if h.OS == "windows" {
536				cmd := fmt.Sprintf(
537					"%s; Set-Location -Path $runnerDir; & .\\config.cmd remove --token %s",
538					windowsRunnerDirAssignment(h, "runnerDir", instanceName),
539					powerShellSingleQuoted(removeToken),
540				)
541				h.RunShell(cmd)
542			} else {
543				cmd := fmt.Sprintf("cd %s && ./config.sh remove --token '%s'", dir, removeToken)
544				h.Run(cmd)
545			}
546			fmt.Fprintf(m.out(), "  %s: deregistered\n", instanceName)
547		}
548	
549		if h.OS == "windows" {
550			h.RunShell(fmt.Sprintf("%s; Remove-Item -Recurse -Force $runnerDir", windowsRunnerDirAssignment(h, "runnerDir", instanceName)))
551		} else {
552			h.Run(fmt.Sprintf("rm -rf %s", dir))
553		}
554	
555		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
556		return nil
557	}
