559	func (m *Manager) statusNative(h *host.Host, instanceName string) string {
560		dir := h.RunnerDir(instanceName)
561	
562		if kind, err := autostart.Detect(h, instanceName); err == nil && kind != autostart.KindNone {
563			active, err := autostart.IsServiceActive(h, instanceName, kind)
564			if err != nil {
565				return "unknown"
566			}
567			if active {
568				return "running"
569			}
570			return "stopped"
571		}
572	
573		if h.OS == "windows" {
574			cmd := fmt.Sprintf(
575				"%s; if (-not (Test-Path (Join-Path $runnerDir '.runner'))) { Write-Host 'not installed'; exit 0 }; "+
576					"$pidFile = Join-Path $runnerDir '.runner_pid'; "+
577					"if (-not (Test-Path $pidFile)) { Write-Host 'stopped'; exit 0 }; "+
578					"$p = Get-Content $pidFile; "+
579					"try { Get-Process -Id $p -EA Stop | Out-Null; Write-Host 'running' } catch { Write-Host 'stopped' }",
580				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
581			)
582			out, _ := h.RunShell(cmd)
583			return strings.TrimSpace(out)
584		}
585	
586		cmd := fmt.Sprintf(
587			`d="%s" && `+
588				`if [ ! -f "$d/.runner" ]; then echo "not installed"; exit 0; fi && `+
589				`pid_file="$d/.runner_pid" && `+
590				`if [ ! -f "$pid_file" ]; then echo "stopped"; exit 0; fi && `+
591				`pid=$(cat "$pid_file") && `+
592				`if kill -0 "$pid" 2>/dev/null; then echo "running"; else echo "stopped"; fi`,
593			dir,
594		)
595		out, err := h.Run(cmd)
596		if err != nil {
597			return "unknown"
598		}
599		return strings.TrimSpace(out)
600	}
