602	func (m *Manager) logsNative(h *host.Host, instanceName string) (string, error) {
603		dir := h.RunnerDir(instanceName)
604	
605		if h.OS == "windows" {
606			cmd := fmt.Sprintf(
607				"%s; $logFile = Join-Path $runnerDir 'runner.log'; "+
608					"$diagDir = Join-Path $runnerDir '_diag'; "+
609					"$tailMain = { if (Test-Path $logFile) { $lines = @(Get-Content -LiteralPath $logFile -Tail 50 -EA SilentlyContinue); "+
610					"$j = [string]::Join([Environment]::NewLine, $lines); "+
611					"if ($lines.Count -gt 0 -and ($j -match '\\S')) { $j } else { $null } } else { $null } }; "+
612					"$main = & $tailMain; "+
613					"if ($null -ne $main) { Write-Output $main } "+
614					"elseif (Test-Path $diagDir) { "+
615					"$latest = Get-ChildItem -Path $diagDir -Filter *.log -File -EA SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1; "+
616					"if ($latest) { Write-Output ('--- _diag/' + $latest.Name + ' (last 50 lines) ---'); Get-Content -LiteralPath $latest.FullName -Tail 50 } "+
617					"else { Write-Output 'no logs found' } } "+
618					"else { Write-Output 'no logs found' }",
619				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
620			)
621			return h.RunShell(cmd)
622		}
623	
624		cmd := fmt.Sprintf("tail -50 %s/runner.log 2>/dev/null || echo 'no logs found'", dir)
625		return h.Run(cmd)
626	}
