    // Check external DNS resolution
    out, err = h.Run(`docker run --rm alpine sh -c "nslookup github.com >/dev/null 2>&1 && echo ok || echo failed" 2>/dev/null`)
    out = strings.TrimSpace(out)
    if err != nil || out != "ok" {
